// Code generated by selo gen --lang rust. DO NOT EDIT.

use crate::data::VOTER_UF_NAMES;
use crate::mod11::{self, CheckDigit, Rule, SeloError};

const DV1: CheckDigit = CheckDigit { weights: &[2, 3, 4, 5, 6, 7, 8, 9], rule: Rule::ModRemainder, remainder_to0: &[10, 11], multiply_by10: false, encode_x_at: 0, encode_zero_at: 0 };
const DV2: CheckDigit = CheckDigit { weights: &[7, 8, 9], rule: Rule::ModRemainder, remainder_to0: &[10, 11], multiply_by10: false, encode_x_at: 0, encode_zero_at: 0 };

/// Compute the first check digit over the 8 sequence digits.
fn dv1(d: &str) -> i32 {
    let bytes = d.as_bytes();
    let seq: Vec<i32> = (0..8).map(|i| (bytes[i] - b'0') as i32).collect();
    mod11::compute_digit(mod11::weighted_sum(&seq, DV1.weights, false), &DV1)
}

/// Compute the second check digit over [uf0, uf1, dv1].
fn dv2(d: &str, dv1: i32) -> i32 {
    let bytes = d.as_bytes();
    let vals = [(bytes[8] - b'0') as i32, (bytes[9] - b'0') as i32, dv1];
    mod11::compute_digit(mod11::weighted_sum(&vals, DV2.weights, false), &DV2)
}

/// Report whether value is a well-formed Título Eleitoral.
pub fn validate_voter_id(value: &str) -> bool {
    let d = mod11::only_digits(value);
    if d.len() != 12 {
        return false;
    }
    if mod11::all_equal(&d) {
        return false;
    }
    let bytes = d.as_bytes();
    let uf_code = ((bytes[8] - b'0') as i32) * 10 + (bytes[9] - b'0') as i32;
    if !(1..=28).contains(&uf_code) {
        return false;
    }
    let v1 = dv1(&d);
    let v2 = dv2(&d, v1);
    v1 == (bytes[10] - b'0') as i32 && v2 == (bytes[11] - b'0') as i32
}

/// Group the voter ID as "SSSS SSSS UUDD", or return an error.
pub fn format_voter_id(value: &str) -> Result<String, SeloError> {
    let d = mod11::only_digits(value);
    if d.len() != 12 {
        return Err(SeloError::InvalidLength);
    }
    Ok(format!("{} {} {}", &d[0..4], &d[4..8], &d[8..12]))
}

/// Return the region encoded in the UF code, or an error.
pub fn origin_voter_id(value: &str) -> Result<String, SeloError> {
    let d = mod11::only_digits(value);
    if d.len() != 12 {
        return Err(SeloError::InvalidLength);
    }
    let bytes = d.as_bytes();
    let uf_code = ((bytes[8] - b'0') as i32) * 10 + (bytes[9] - b'0') as i32;
    match VOTER_UF_NAMES.iter().find(|(k, _)| *k == uf_code).map(|(_, v)| *v) {
        Some(name) => Ok(name.to_string()),
        None => Err(SeloError::InvalidFormat),
    }
}

/// Return a random, valid Título Eleitoral (12 digits, unformatted).
pub fn generate_voter_id() -> String {
    loop {
        let mut d: Vec<i32> = vec![0; 12];
        for i in 0..8 {
            d[i] = mod11::rand_int(9) as i32;
        }
        let uf = 1 + mod11::rand_int(27) as i32;
        d[8] = uf / 10;
        d[9] = uf % 10;
        let s: String = d[0..10].iter().map(|n| n.to_string()).collect();
        let v1 = dv1(&s);
        d[10] = v1;
        d[11] = dv2(&s, v1);
        let out: String = d.iter().map(|n| n.to_string()).collect();
        if !mod11::all_equal(&out) {
            return out;
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn vector() -> serde_json::Value {
        let p = concat!(env!("CARGO_MANIFEST_DIR"), "/vectors/voter_id.json");
        let s = std::fs::read_to_string(p).expect("read vector");
        serde_json::from_str(&s).expect("parse vector")
    }

    #[test]
    fn validate_cases() {
        for case in vector()["validate"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let valid = case["valid"].as_bool().unwrap();
            assert_eq!(valid, validate_voter_id(input), "validate {}", input);
        }
    }

    #[test]
    fn format_cases() {
        for case in vector()["format"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let is_error = case
                .get("error")
                .and_then(|e| e.as_str())
                .map(|e| !e.is_empty())
                .unwrap_or(false);
            if is_error {
                assert!(format_voter_id(input).is_err(), "format expected err {}", input);
            } else {
                let want = case["output"].as_str().unwrap();
                assert_eq!(want, format_voter_id(input).unwrap(), "format {}", input);
            }
        }
    }

    #[test]
    fn origin_cases() {
        if let Some(arr) = vector().get("origin").and_then(|o| o.as_array()) {
            for case in arr {
                let input = case["input"].as_str().unwrap();
                let want = case["output"].as_str().unwrap();
                assert_eq!(want, origin_voter_id(input).unwrap(), "origin {}", input);
            }
        }
    }

    #[test]
    fn generate_round_trip() {
        for _ in 0..100 {
            let v = generate_voter_id();
            assert!(validate_voter_id(&v), "generate produced invalid: {}", v);
        }
    }
}
